arguments.prompt:
You are implementing a Blazor Web App for a logistics company that tracks shipments. The project is already scaffolded at `/tmp/sv-133f04b0f3d349b181d32b6e47fb2f47/ShipmentTracker/` with Interactive Auto Global mode and Individual authentication.

Project structure:
- Server project: `ShipmentTracker/ShipmentTracker/`
- Client project: `ShipmentTracker/ShipmentTracker.Client/`
- Solution file: `ShipmentTracker/ShipmentTracker.sln`

The server Program.cs already has Identity, EF Core with SQLite, and Auto render mode configured. The client Program.cs has auth deserialization.

## What to implement

### 1. Shared models (in the `.Client` project since interactive components need them)

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

### 2. Service interface (in `.Client` project)

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail);
    Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 3. Client-side implementation using HttpClient

Create `ShipmentTracker.Client/Services/ShipmentServiceClient.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

public class ShipmentServiceClient(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await httpClient.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await httpClient.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
```

### 4. Register HttpClient and service in client Program.cs

Edit `ShipmentTracker.Client/Program.cs` to add:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddHttpClient<IShipmentService, ShipmentServiceClient>(client =>
{
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress);
});

await builder.Build().RunAsync();
```

Wait — WebAssemblyHostBuilder doesn't have `AddHttpClient`. Use this instead:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ShipmentServiceClient>();

await builder.Build().RunAsync();
```

### 5. Server-side EF entity and DbContext extension

Create `ShipmentTracker/ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
namespace ShipmentTracker.Data;

using ShipmentTracker.Client.Models;

public class ShipmentEntity
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}
```

Edit `ShipmentTracker/ShipmentTracker/Data/ApplicationDbContext.cs` to add:
```csharp
public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();
```

### 6. Server-side service implementation

Create `ShipmentTracker/ShipmentTracker/Services/ShipmentServiceServer.cs`:
```csharp
namespace ShipmentTracker.Services;

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

public class ShipmentServiceServer(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(e => MapToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await db.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .Select(e => MapToModel(e))
            .ToListAsync();
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id) ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = status;
        if (status == ShipmentStatus.Delivered)
            entity.ActualDelivery = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return MapToModel(entity);
    }

    private static Shipment MapToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        ShippedDate = e.ShippedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        ActualDelivery = e.ActualDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description
    };
}
```

### 7. API endpoints

Create `ShipmentTracker/ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
namespace ShipmentTracker.Endpoints;

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            return await db.Shipments.Select(e => new Shipment
            {
                Id = e.Id,
                TrackingNumber = e.TrackingNumber,
                Origin = e.Origin,
                Destination = e.Destination,
                Status = e.Status,
                ShippedDate = e.ShippedDate,
                EstimatedDelivery = e.EstimatedDelivery,
                ActualDelivery = e.ActualDelivery,
                CustomerEmail = e.CustomerEmail,
                Description = e.Description
            }).ToListAsync();
        });

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (entity is null) return Results.NotFound();
            return Results.Ok(new Shipment
            {
                Id = entity.Id,
                TrackingNumber = entity.TrackingNumber,
                Origin = entity.Origin,
                Destination = entity.Destination,
                Status = entity.Status,
                ShippedDate = entity.ShippedDate,
                EstimatedDelivery = entity.EstimatedDelivery,
                ActualDelivery = entity.ActualDelivery,
                CustomerEmail = entity.CustomerEmail,
                Description = entity.Description
            });
        });

        group.MapGet("customer/{email}", async (string email, ApplicationDbContext db) =>
        {
            return await db.Shipments
                .Where(s => s.CustomerEmail == Uri.UnescapeDataString(email))
                .Select(e => new Shipment
                {
                    Id = e.Id,
                    TrackingNumber = e.TrackingNumber,
                    Origin = e.Origin,
                    Destination = e.Destination,
                    Status = e.Status,
                    ShippedDate = e.ShippedDate,
                    EstimatedDelivery = e.EstimatedDelivery,
                    ActualDelivery = e.ActualDelivery,
                    CustomerEmail = e.CustomerEmail,
                    Description = e.Description
                }).ToListAsync();
        });

        group.MapPut("{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();
            entity.Status = status;
            if (status == ShipmentStatus.Delivered)
                entity.ActualDelivery = DateTime.UtcNow;
            await db.SaveChangesAsync();
            return Results.Ok(new Shipment
            {
                Id = entity.Id,
                TrackingNumber = entity.TrackingNumber,
                Origin = entity.Origin,
                Destination = entity.Destination,
                Status = entity.Status,
                ShippedDate = entity.ShippedDate,
                EstimatedDelivery = entity.EstimatedDelivery,
                ActualDelivery = entity.ActualDelivery,
                CustomerEmail = entity.CustomerEmail,
                Description = entity.Description
            });
        });
    }
}
```

### 8. Register server-side service and endpoints in server Program.cs

In `ShipmentTracker/ShipmentTracker/Program.cs`, add BEFORE `var app = builder.Build();`:
```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServiceServer>();
```

And add the using statements at the top:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
using ShipmentTracker.Endpoints;
```

AFTER `app.MapAdditionalIdentityEndpoints();` add:
```csharp
app.MapShipmentEndpoints();
```

The server project needs a reference to the Client project. Check if it already has one (it likely does from the template). If not, add `<ProjectReference Include="..\ShipmentTracker.Client\ShipmentTracker.Client.csproj" />`.

### 9. Pages in the Client project

**Remove default template pages** - delete `Counter.razor` and `Weather.razor` from the Client project's Pages folder if they exist.

**Create `ShipmentTracker.Client/Pages/Home.razor`:**
```razor
