@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Shipment Tracker</h1>
<p class="lead">Welcome to the logistics shipment tracking system.</p>

<div class="row">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Dispatcher Dashboard</h5>
                <p class="card-text">View and manage all shipments, update statuses, and monitor deliveries.</p>
                <a href="/dispatcher" class="btn btn-primary">Go to Dashboard</a>
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Track a Shipment</h5>
                <p class="card-text">Check the status and estimated delivery of your shipment.</p>
                <a href="/track" class="btn btn-outline-primary">Track Shipment</a>
            </div>
        </div>
    </div>
</div>
```

**Create `ShipmentTracker.Client/Pages/Dispatcher.razor`:**
```razor
@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3 row">
